import logging
from pathlib import Path

from peewee import *
from peewee_migrate import Router
from peewee_async import PooledPostgresqlExtDatabase

from app.config import DB_HOST, DB_PORT, DB_NAME, DB_USER, DB_PASSWORD

APP_DIR = Path(__file__).resolve().parent.parent
MIGRATION_DIR = APP_DIR / "migrations"

# Setup logger
log = logging.getLogger(__name__)
logging.basicConfig(level=logging.INFO, format="%(asctime)s [%(levelname)s] %(message)s")

try:
    log.info("Connecting to the database...")
    
    # Create pooled AsyncPostgresql connection using PooledPostgresqlExtDatabase
    # This uses aiopg under the hood for true async support
    DB = PooledPostgresqlExtDatabase(
        DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
        host=DB_HOST,
        port=DB_PORT or 5432,
        autorollback=True,
        autoconnect=True,
        pool_params={
            "minsize": 1,
            "maxsize": 20,
            "timeout": 30
        }
    )
    
    log.info(f"Connected to PostgreSQL database with async connection pooling (maxsize=20).")

    # Allow sync operations during initialization/migrations
    log.info("Starting migrations...")
    with DB.allow_sync():
        router = Router(
            DB,
            migrate_dir=MIGRATION_DIR,
            logger=log
        )
        router.run()
    log.info("Migrations completed.")

    # Disable sync after initialization for async-only mode
    DB.set_allow_sync(False)

    if DB.is_closed():
        log.info("Opening database connection...")
        DB.connect(reuse_if_open=True)
    else:
        log.info(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   "Database connection is already open.")

except Exception as e:
    log.exception(f"An error occurred: {e}")
    raise
